import 'package:flutter/material.dart';
import 'package:audioplayers/audioplayers.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';
import '../services/api_service.dart';

class AudioChunkPlayer extends StatefulWidget {
  final double angle;
  final double velocity;
  final double gravity;
  final String? customFormula;
  final String language;

  const AudioChunkPlayer({
    super.key,
    required this.angle,
    required this.velocity,
    required this.gravity,
    this.customFormula,
    this.language = 'te-IN',
  });

  @override
  State<AudioChunkPlayer> createState() => _AudioChunkPlayerState();
}

class _AudioChunkPlayerState extends State<AudioChunkPlayer> {
  final AudioPlayer _audioPlayer = AudioPlayer();
  String? _combinedAudioUrl;
  bool _isLoading = true;
  bool _isPlaying = false;
  String _selectedLanguage = 'te-IN';

  @override
  void initState() {
    super.initState();
    _selectedLanguage = widget.language;
    _audioPlayer.onPlayerComplete.listen((_) {
      if (mounted) {
        setState(() {
          _isPlaying = false;
        });
      }
    });
    _loadCombinedAudio();
  }

  @override
  void didUpdateWidget(AudioChunkPlayer oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.angle != widget.angle ||
        oldWidget.velocity != widget.velocity ||
        oldWidget.gravity != widget.gravity) {
      _loadCombinedAudio();
    }
  }

  @override
  void dispose() {
    _audioPlayer.dispose();
    super.dispose();
  }

  Future<void> _loadCombinedAudio() async {
    setState(() {
      _isLoading = true;
      _combinedAudioUrl = null;
    });

    try {
      final response = await http
          .post(
            Uri.parse('${ApiService.apiBaseUrl}/api/chunks'),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'angle': widget.angle,
              'velocity': widget.velocity,
              'gravity': widget.gravity,
              'custom_formula': widget.customFormula,
              'include_formula': widget.customFormula != null &&
                  widget.customFormula!.isNotEmpty,
              'language': _selectedLanguage,
            }),
          )
          .timeout(const Duration(seconds: 120));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);

        if (mounted) {
          setState(() {
            _combinedAudioUrl = data['combined_audio_url'];
            _isLoading = false;
          });
        }
      } else {
        if (mounted) {
          setState(() {
            _isLoading = false;
          });
          _showError('Failed to load explanation');
        }
      }
    } catch (e) {
      debugPrint('Error loading audio: $e');
      if (mounted) {
        setState(() {
          _isLoading = false;
        });
        _showError('Error loading explanation');
      }
    }
  }

  Future<void> _playExplanation() async {
    if (_combinedAudioUrl == null || _combinedAudioUrl!.isEmpty) {
      _showError('Audio not available');
      return;
    }

    if (_isPlaying) {
      await _audioPlayer.stop();
      setState(() {
        _isPlaying = false;
      });
      return;
    }

    setState(() {
      _isPlaying = true;
    });

    try {
      await _audioPlayer.stop();
      await _audioPlayer.play(UrlSource(_combinedAudioUrl!));
    } catch (e) {
      debugPrint('Error playing audio: $e');
      setState(() {
        _isPlaying = false;
      });
      _showError('Error playing audio');
    }
  }

  Future<void> _stop() async {
    await _audioPlayer.stop();
    setState(() {
      _isPlaying = false;
    });
  }

  void _showError(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        duration: const Duration(seconds: 2),
      ),
    );
  }

  void _toggleLanguage() {
    setState(() {
      _selectedLanguage = _selectedLanguage == 'te-IN' ? 'en-IN' : 'te-IN';
    });
    _loadCombinedAudio();
  }

  @override
  Widget build(BuildContext context) {
    return Card(
      margin: const EdgeInsets.all(8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Padding(
            padding: const EdgeInsets.all(12),
            child: Row(
              children: [
                const Icon(Icons.audiotrack, color: Colors.deepPurple),
                const SizedBox(width: 8),
                Expanded(
                  child: Text(
                    'Projectile Motion Explanation',
                    style: Theme.of(context).textTheme.titleMedium,
                  ),
                ),
                TextButton.icon(
                  onPressed: _toggleLanguage,
                  icon: Icon(
                    _selectedLanguage == 'te-IN'
                        ? Icons.language
                        : Icons.translate,
                    size: 18,
                  ),
                  label: Text(
                    _selectedLanguage == 'te-IN' ? 'తెలుగు' : 'English',
                    style: const TextStyle(fontSize: 12),
                  ),
                ),
              ],
            ),
          ),
          const Divider(height: 1),
          if (_isLoading)
            const Padding(
              padding: EdgeInsets.all(32),
              child: Center(
                child: Column(
                  children: [
                    CircularProgressIndicator(),
                    SizedBox(height: 16),
                    Text('Generating full explanation...'),
                  ],
                ),
              ),
            )
          else
            Padding(
              padding: const EdgeInsets.all(16),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  ElevatedButton.icon(
                    onPressed: _playExplanation,
                    icon: Icon(_isPlaying ? Icons.pause : Icons.play_arrow),
                    label: Text(_isPlaying ? 'Pause' : 'Play Full Explanation'),
                    style: ElevatedButton.styleFrom(
                      backgroundColor: Colors.deepPurple,
                      foregroundColor: Colors.white,
                      padding: const EdgeInsets.symmetric(
                        horizontal: 24,
                        vertical: 12,
                      ),
                    ),
                  ),
                  const SizedBox(width: 12),
                  IconButton(
                    onPressed: _stop,
                    icon: const Icon(Icons.stop),
                    tooltip: 'Stop',
                    style: IconButton.styleFrom(
                      backgroundColor: Colors.grey[200],
                    ),
                  ),
                  IconButton(
                    onPressed: _loadCombinedAudio,
                    icon: const Icon(Icons.refresh),
                    tooltip: 'Refresh',
                    style: IconButton.styleFrom(
                      backgroundColor: Colors.grey[200],
                    ),
                  ),
                ],
              ),
            ),
        ],
      ),
    );
  }
}

